RuleSet.GenFile:
#!/bin/bash # # @(#) $GenPackageDir$/$GenFileName$ $MssBashScriptLicense$ $parsePgSqlArgs$$validatePgSqlArgs$ echo "Dropping old schema $lower DbSchemaName$ for $${pguser}" echo "Dropping old schema $lower DbSchemaName$ for $${pguser}" >>$${logfilename}
psql -h $${pghost} $${PGPORT} -U $${pguser} -a -e -c "drop schema $lower DbSchemaName$" >>$${logfilename} 2>&1
echo "Creating schema $DbSchemaName$ in database $${pgdb} for $${pguser}" echo "Creating schema $DbSchemaName$ in database $${pgdb} for $${pguser}" >>$${logfilename}
psql -h $${pghost} $${PGPORT} -d $${pgdb} -U $${pguser} -a -e -c "create schema $lower DbSchemaName$" >>$${logfilename} 2>&1
$exec_CreateAllTables$$exec_CreateAllIndexes$$exec_CreateAllRelations$$exec_CreateAllSequences$$exec_CreateAllTypes$$exec_CreateAllStoredProcs$$exec_LoadAllData$$exec_CreateAllTriggers$ exit 0

RuleSet.GenRule:
#
#	Create the database tables
#
if [ -f ./$dbadminfilename_CreateAllTables$ ]; then
	echo "	Creating database tables ..."
	echo "" >>$${logfilename}
	echo "#" >>$${logfilename}
	echo "#	Executing script $dbadminfilename_CreateAllTables$" >>$${logfilename}
	echo "#" >>$${logfilename}
	./$dbadminfilename_CreateAllTables$ -H $${pghost} $${PASSPGPORT} -d $${pgdb} -U $${pguser} -P $${pgpwd} -L $${logfilename}
fi

#
#	Create the database indexes
#
if [ -f ./$dbadminfilename_CreateAllIndexes$ ]; then
	echo "	Creating database indexes ..."
	echo "#" >>$${logfilename}
	echo "#	Executing script $dbadminfilename_CreateAllIndexes$" >>$${logfilename}
	echo "#" >>$${logfilename}
	./$dbadminfilename_CreateAllIndexes$ -H $${pghost} $${PASSPGPORT} -d $${pgdb} -U $${pguser} -P $${pgpwd} -L $${logfilename}
fi

#
#	Create the database relations
#
if [ -f ./$dbadminfilename_CreateAllRelations$ ]; then
	echo "	Creating database relations ..."
	echo "" >>$${logfilename}
	echo "#" >>$${logfilename}
	echo "#	Executing script $dbadminfilename_CreateAllRelations$" >>$${logfilename}
	echo "#" >>$${logfilename}
	./$dbadminfilename_CreateAllRelations$ -H $${pghost} $${PASSPGPORT} -d $${pgdb} -U $${pguser} -P $${pgpwd} -L $${logfilename}
fi

#
#	Create the database sequences
#
if [ -f ./$dbadminfilename_CreateAllSequences$ ]; then
	echo "	Creating database sequences..."
	echo "" >>$${logfilename}
	echo "#" >>$${logfilename}
	echo "#	Executing script $dbadminfilename_CreateAllSequences$" >>$${logfilename}
	echo "#" >>$${logfilename}
	./$dbadminfilename_CreateAllSequences$ -H $${pghost} $${PASSPGPORT} -d $${pgdb} -U $${pguser} -P $${pgpwd} -L $${logfilename}
fi

#
#	Create the return record types for the stored procedures
#
if [ -f ./$dbadminfilename_CreateAllTypes$ ]; then
	echo "	Creating database types..."
	echo "" >>$${logfilename}
	echo "#" >>$${logfilename}
	echo "#	Executing script $dbadminfilename_CreateAllTypes$" >>$${logfilename}
	echo "#" >>$${logfilename}
	./$dbadminfilename_CreateAllTypes$ -H $${pghost} $${PASSPGPORT} -d $${pgdb} -U $${pguser} -P $${pgpwd} -L $${logfilename}
fi

#
#	Create the stored procedures
#
if [ -f ./$dbadminfilename_CreateAllStoredProcs$ ]; then
	echo "	Creating stored procedures..."
	echo "" >>$${logfilename}
	echo "#" >>$${logfilename}
	echo "#	Executing script $dbadminfilename_CreateAllStoredProcs$" >>$${logfilename}
	echo "#" >>$${logfilename}
	./$dbadminfilename_CreateAllStoredProcs$ -H $${pghost} $${PASSPGPORT} -d $${pgdb} -U $${pguser} -P $${pgpwd} -L $${logfilename}
fi

#
#	Load initial data
#
if [ -f ./$dbadminfilename_LoadAllData$ ]; then
	echo "	Loading initial data ..."
	echo "" >>$${logfilename}
	echo "#" >>$${logfilename}
	echo "#	Executing script $dbadminfilename_LoadAllData$" >>$${logfilename}
	echo "#" >>$${logfilename}
	./$dbadminfilename_LoadAllData$ -H $${pghost} $${PASSPGPORT} -d $${pgdb} -U $${pguser} -P $${pgpwd} -L $${logfilename}
fi

#
#	Create the database triggers
#
if [ -f ./$dbadminfilename_CreateAllTriggers$ ]; then
	echo "	Creating database triggers ..."
	echo "" >>$${logfilename}
	echo "#" >>$${logfilename}
	echo "#	Executing script $dbadminfilename_CreateAllTriggers$" >>$${logfilename}
	echo "#" >>$${logfilename}
	./$dbadminfilename_CreateAllTriggers$ -H $${pghost} $${PASSPGPORT} -d $${pgdb} -U $${pguser} -P $${pgpwd} -L $${logfilename}
fi
